import{_ as t,o as i,c as a,ag as r}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Interpretive Lens","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interpretive-lens.md","filePath":"guide/interpretive-lens.md","lastUpdated":1772287587000}'),o={name:"guide/interpretive-lens.md"};function n(s,e,l,h,d,p){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="interpretive-lens" tabindex="-1">Interpretive Lens <a class="header-anchor" href="#interpretive-lens" aria-label="Permalink to &quot;Interpretive Lens&quot;">​</a></h1><p>The Interpretive Lens lets you tell the AI which medical experts, researchers, or scientific frameworks to draw on when analyzing your results. Instead of a one-size-fits-all interpretation, the AI considers the perspective of the thinkers and paradigms you care about.</p><h2 id="where-to-find-it" tabindex="-1">Where to Find It <a class="header-anchor" href="#where-to-find-it" aria-label="Permalink to &quot;Where to Find It&quot;">​</a></h2><p>The Interpretive Lens appears as a <strong>full-width card with a purple left border</strong> near the top of the dashboard, just above the Focus Card. Click it to open the editor.</p><h2 id="what-to-write" tabindex="-1">What to Write <a class="header-anchor" href="#what-to-write" aria-label="Permalink to &quot;What to Write&quot;">​</a></h2><p>The lens is a free-form text field. Write the names of experts, schools of thought, or scientific paradigms you want the AI to keep in mind. Examples:</p><ul><li>Names of specific researchers or clinicians (e.g., practitioners focused on functional medicine, mitochondrial biology, hormesis, or longevity research)</li><li>Scientific frameworks (e.g., circadian biology, evolutionary medicine, ancestral health)</li><li>Dietary or lifestyle philosophies you follow</li><li>Any combination of the above</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The AI does not need you to explain who these people are. If it knows their published work, it will apply their perspective to your data automatically.</p></div><h2 id="how-it-shapes-ai-analysis" tabindex="-1">How It Shapes AI Analysis <a class="header-anchor" href="#how-it-shapes-ai-analysis" aria-label="Permalink to &quot;How It Shapes AI Analysis&quot;">​</a></h2><p>Every AI interaction in getbased — the Focus Card, the chat panel, and per-marker explanations — includes your Interpretive Lens in the context. The AI will:</p><ul><li>Frame its analysis through the paradigms you listed</li><li>Draw on the research traditions those experts represent</li><li>Flag where your results align or conflict with those frameworks</li><li>Prioritize the markers and factors those frameworks consider important</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>If you write something like <em>&quot;circadian biology, UV and mitochondrial health, ancestral diet&quot;</em> in your lens, the AI will consider light exposure, vitamin D, and metabolic markers through that framework rather than giving you a standard conventional-medicine reading.</p><h2 id="editing-and-saving" tabindex="-1">Editing and Saving <a class="header-anchor" href="#editing-and-saving" aria-label="Permalink to &quot;Editing and Saving&quot;">​</a></h2><p>Click the card to open the editor. Type or paste your lens text, then click <strong>Save</strong>. The card updates immediately on the dashboard.</p><p>The Interpretive Lens is included in your <a href="/docs/guide/json-export-import.html">JSON export</a> and restored on import.</p>',16)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
